        $builder->startVector(8, $numElems, 8);
    }

    /**
     * @param FlatBufferBuilder $builder
     * @param ulong
     * @return void
     */
    public static function addCOMPUTED_AT(FlatBufferBuilder $builder, $COMPUTED_AT)
    {
        $builder->addUlongX(18, $COMPUTED_AT, 0);
    }

    /**
     * @param FlatBufferBuilder $builder
     * @param VectorOffset
     * @return void
     */
    public static function addSIGNATURE(FlatBufferBuilder $builder, $SIGNATURE)
    {
        $builder->addOffsetX(19, $SIGNATURE, 0);
    }

    /**
     * @param FlatBufferBuilder $builder
     * @param array offset array
     * @return int vector offset
     */
    public static function createSIGNATUREVector(FlatBufferBuilder $builder, array $data)
    {
        $builder->startVector(1, count($data), 1);
        for ($i = count($data) - 1; $i >= 0; $i--) {
            $builder->putByte($data[$i]);
        }
        return $builder->endVector();
    }

    /**
     * @param FlatBufferBuilder $builder
     * @param int $numElems
     * @return void
     */
    public static function startSIGNATUREVector(FlatBufferBuilder $builder, $numElems)
    {
        $builder->startVector(1, $numElems, 1);
    }

    /**
     * @param FlatBufferBuilder $builder
     * @return int table offset
     */
    public static function endCVG(FlatBufferBuilder $builder)
    {
        $o = $builder->endObject();
        $builder->required($o, 4);  // COVERAGE_ID
        return $o;
    }

    public static function finishCVGBuffer(FlatBufferBuilder $builder, $offset)
    {
        $builder->finish($offset, "$CVG");
    }
}
